All I did was add the following to [server/views.js](https://github.com/galenmaly/lighterpack/blob/master/server/views.js). Modified from the CSV endpoint.

```node
router.get('/json/:id', (req, res) => {
    const id = req.params.id;

    if (!id) {
        res.status(400).send('No list specified!');
        return;
    }

    db.users.find({ 'library.lists.externalId': id }, (err, users) => {
        if (err) {
            res.status(500).send('An error occurred.');
            return;
        }

        if (!users.length) {
            res.status(400).send('Invalid list specified.');
            return;
        }

        const library = new Library();
        let list;

        if (!users[0] || typeof (users[0].library) === 'undefined') {
            logWithRequest(req, `Undefined users[0] for library with list ID ${id}`);
            res.status(500).send('Unknown error.');
        }

        library.load(users[0].library);
        for (var i in library.lists) {
            if (library.lists[i].externalId && library.lists[i].externalId == id) {
                library.defaultListId = library.lists[i].id;
                list = library.lists[i];
                break;
            }
        }

        let out = {};
        out['name'] = list.name;
        out['categories'] = [];

        for (var i in list.categoryIds) {
            const category = library.getCategoryById(list.categoryIds[i]);
            if (category) {
                let catJSON = {};
                catJSON['category.name'] = category.name;
                catJSON['category.items'] = [];
                for (const j in category.categoryItems) {
                    const categoryItem = category.categoryItems[j];

                    if (categoryItem) {
                        itemJSON = {};
                        const item = library.getItemById(categoryItem.itemId);

                        itemJSON['item.name'] = item.name;
                        itemJSON['item.description'] = item.description;
                        itemJSON['item.qty'] = categoryItem.qty;
                        itemJSON['item.weight'] = weightUtils.MgToWeight(item.weight, item.authorUnit);
                        itemJSON['item.weight.unit'] = item.authorUnit;
                        itemJSON['item.url'] = item.url;
                        itemJSON['item.price'] = item.price;
                        itemJSON['item.worn'] = categoryItem.worn ? 'Worn' : '';
                        itemJSON['item.consumable'] = categoryItem.consumable ? 'Consumable' : '';

                        catJSON['category.items'].push(itemJSON);
                    }
                }
                out['categories'].push(catJSON);
            }
        }

        res.json(out);
    });
});
```

As a temporary fix you could inject your own CSS via a browser extension like [User JavaScript and CSS](https://chrome.google.com/webstore/detail/user-javascript-and-css/nbhcbdghjpllgmfilhnhkllmkecfmpld)

@electricmessiah I like the idea, since. Currently there is no way in CSS to target a parent element, for instance to highlight a whole row. Theoretically one would need JavaScript to do any content based changes, but luckily LighterPack keeps the customization spirit of our scene alive in that it puts invalid HTML content inside some elements to make such customization possible. So, consider everything here as a 'hack'.

You can target specific quantities via CSS. Instead of emphasizing everything that has a quantity of greater than or equal to 1, I have decided to only mark items that have a quantity of zero. _(For me that's stuff I'm not sure I want to take with me on a trip.)_:


![](https://cl.ly/lqvA/lighterpackk-css1.png)

    .lpQtyCell[qty0] {
        color: hsla(206, 12%, 56%, 0.64);          ;
        background: hsla(206, 12%, 56%, 0.64);
    }

Since LightPack uses the `qty` attribute as a hack, one can't use the `:not` selector trick. But you could simply list a ton of quantity selectors like to mimic a `≥` rule like  this:

![](https://cl.ly/lqTn/lighterpackk-css2.png)

    .lpQtyCell[qty1],
    .lpQtyCell[qty2],
    .lpQtyCell[qty3],
    .lpQtyCell[qty4],
    .lpQtyCell[qty5],
    .lpQtyCell[qty6],
    .lpQtyCell[qty7] {
        color: #ed676f;
        background: hsla(111, 78%, 91%, 0.35);
    }

**NOTE:** _This is for shared sites only. You might have to adjust the CSS a bit to have the same styling when you're logged in to your account._

@johnabela You can hide the complete column by adding this CSS snippet:

    .lpItems.lpDataTable .lpHeader .lpQtyCell, span.lpQtyCell.lpNumber {
        display: none;
    }

